def classify_material(origin, is_processed):
    if origin in ['plant', 'animal', 'enzyme', 'bacteria', 'fungus', 'yeast'] and is_processed:
        return 'bio-based (processed)'
    elif origin in ['plant', 'animal', 'enzyme', 'bacteria', 'fungus', 'yeast']:
        return 'bio-based (unprocessed)'
    else:
        return 'traditional'

# Example usage:
print(classify_material('plant', True))  # Output: bio-based (processed)
print(classify_material('animal', False)) # Output: bio-based (unprocessed)
print(classify_material('mineral', True)) # Output: traditional
